// ==========================================
// ErrorBoundary
// ==========================================
export class ErrorBoundary extends Component {
    constructor(props) { super(props); this.state = { hasError: false, error: null }; }
    static getDerivedStateFromError(e) { return { hasError: true, error: e }; }
    render() {
        if (this.state.hasError) return (
            <div className="p-8 text-red-600 flex flex-col items-center justify-center h-screen bg-white">
                <h2 className="text-xl font-bold mb-2">组件渲染错误</h2>
                <p className="text-sm text-slate-500 mb-4">{this.state.error?.message}</p>
                <button onClick={() => window.location.reload()} className="px-4 py-2 bg-slate-800 text-white rounded-lg">刷新页面</button>
            </div>
        );
        return this.props.children;
    }
}
